import React, { useState } from "react";
import api from "../api";
import { useNavigate } from "react-router-dom";

const CreateEvent = () => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    title: "",
    description: "",
    eventType: "normal", // normal or merchandise
    eligibility: "",
    registrationDeadline: "",
    startDate: "",
    endDate: "",
    registrationLimit: 1,
    registrationFee: 0,
    tags: "",
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    try {
      const token = localStorage.getItem("token");
      const payload = {
        ...formData,
        tags: formData.tags.split(",").map((tag) => tag.trim()), // convert CSV to array
      };
      const response = await api.post("/events", payload, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });
      alert("Event created successfully!");
      navigate("/organizer-dashboard");
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.message || "Failed to create event");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container mx-auto p-4">
      <h1 className="text-2xl font-bold mb-4">Create Event</h1>

      {error && <p className="text-red-500 mb-2">{error}</p>}

      <form onSubmit={handleSubmit} className="space-y-4 max-w-lg">
        <input
          type="text"
          name="title"
          placeholder="Event Name"
          value={formData.title}
          onChange={handleChange}
          className="w-full p-2 border rounded"
          required
        />
        <textarea
          name="description"
          placeholder="Event Description"
          value={formData.description}
          onChange={handleChange}
          className="w-full p-2 border rounded"
          required
        />
        <select
          name="eventType"
          value={formData.eventType}
          onChange={handleChange}
          className="w-full p-2 border rounded"
        >
          <option value="normal">Normal Event</option>
          <option value="merchandise">Merchandise Event</option>
        </select>
        <input
          type="text"
          name="eligibility"
          placeholder="Eligibility (e.g., IIIT Students)"
          value={formData.eligibility}
          onChange={handleChange}
          className="w-full p-2 border rounded"
        />
        <label className="block">
          Registration Deadline:
          <input
            type="datetime-local"
            name="registrationDeadline"
            value={formData.registrationDeadline}
            onChange={handleChange}
            className="w-full p-2 border rounded mt-1"
            required
          />
        </label>
        <label className="block">
          Event Start Date:
          <input
            type="datetime-local"
            name="startDate"
            value={formData.startDate}
            onChange={handleChange}
            className="w-full p-2 border rounded mt-1"
            required
          />
        </label>
        <label className="block">
          Event End Date:
          <input
            type="datetime-local"
            name="endDate"
            value={formData.endDate}
            onChange={handleChange}
            className="w-full p-2 border rounded mt-1"
            required
          />
        </label>
        <input
          type="number"
          name="registrationLimit"
          placeholder="Registration Limit"
          value={formData.registrationLimit}
          onChange={handleChange}
          className="w-full p-2 border rounded"
          min={1}
          required
        />
        <input
          type="number"
          name="registrationFee"
          placeholder="Registration Fee (INR)"
          value={formData.registrationFee}
          onChange={handleChange}
          className="w-full p-2 border rounded"
          min={0}
        />
        <input
          type="text"
          name="tags"
          placeholder="Tags (comma separated)"
          value={formData.tags}
          onChange={handleChange}
          className="w-full p-2 border rounded"
        />

        <button
          type="submit"
          disabled={loading}
          className="bg-blue-500 text-white px-4 py-2 rounded hover:bg-blue-600"
        >
          {loading ? "Creating..." : "Create Event"}
        </button>
      </form>
    </div>
  );
};

export default CreateEvent;
